const _distance_thrower = {title: "Distance Thrower", jsx: <><h2 id="feat-distance_thrower-distance-thrower-combat">Distance Thrower (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 97</Link></p>
<p>You are accurate with thrown weapons at longer ranges than normal.<br/><strong>Prerequisites:</strong> Str 13.<br/><strong>Benefit:</strong> With a thrown weapon, you reduce your penalty on ranged attack rolls due to range by 2.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-distance_thrower--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-distance_thrower-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 118</Link><br/>When making an attack with a thrown weapon, you can spend 2 stamina points to reduce your penalty on ranged attack rolls due to range by an additional 4.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-distance_thrower--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Distance Thrower</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 63</Link><br/>There's virtually no limit to your powerful throwing arm.<br/><strong>Prerequisites:</strong> Str 17, Distance Thrower.<br/><strong>Benefit:</strong> Thrown weapons wielded by you have twice their normal range.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _distant_delivery = {title: "Distant Delivery", jsx: <><h2 id="feat-distant_delivery-distant-delivery">Distant Delivery</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 132</Link></p>
<p>Your <Link to="/sidekick/phantom">phantom</Link> can deliver spells at a greater range than usual.<br/><strong>Prerequisites:</strong> Phantom class feature, phantom with the deliver touch spells ability.<br/><strong>Benefit:</strong> The distance from you at which your phantom can deliver touch spells increases by 20 feet.</p>
</>};
const _distant_jinx = {title: "Distant Jinx", jsx: <><h2 id="feat-distant_jinx-distant-jinx">Distant Jinx</h2>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion pg. 27</Link></p>
<p>Your jinx can affect creatures from farther away than normal.<br/><strong>Prerequisites:</strong> Halfling Jinx trait.<br/><strong>Benefit:</strong> The range of your jinx increases by 30 feet.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects stack.</p>
</>};
const _distant_spell_link = {title: "Distant Spell Link", jsx: <><h2 id="feat-distant_spell_link-distant-spell-link">Distant Spell Link</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 12</Link></p>
<p>You can share spells and grant touch spells to your companion creature over a great distance.<br/><strong>Prerequisites:</strong> <Link to="/feat/enlarge_spell">Enlarge Spell</Link> or <Link to="/feat/reach_spell">Reach Spell</Link>; animal companion, eidolon, familiar, or other allied creature with the share spells ability.<br/><strong>Benefit:</strong> The range of your allied creature's share spells ability increases to close (25 feet + 5 feet for every 2 levels) as long as you have line of effect to the creature when you cast the shared spell. If your allied creature has the deliver touch spells ability, you can designate your allied creature as the spell's source when you cast a touch spell as long as you are within close range of it. The creature must still deliver the touch spell at its touch range.<br/><strong>Normal:</strong> You must be adjacent to your familiar to share spells with it or designate touch spells for it to deliver.</p>
</>};
const _distracting_charge = {title: "Distracting Charge", jsx: <><h2 id="feat-distracting_charge-distracting-charge-combat-teamwork">Distracting Charge (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 144</Link></p>
<p>Your ally's charge exposes an opening you can exploit.<br/><strong>Benefit:</strong> When your ally with this feat uses the <Link to="/rule/charge">charge</Link> action and hits, you gain a +2 bonus on your next attack roll against the target of that charge. This bonus must be used before your ally's next turn, or it is lost.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-distracting_charge--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-distracting_charge-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 118</Link><br/>You can spend 1 stamina point when an ally with this feat charges but misses with the charge attack. When you do, you can still gain the benefit of this feat when you charge.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _distracting_explosion = {title: "Distracting Explosion", jsx: <><h2 id="feat-distracting_explosion-distracting-explosion">Distracting Explosion</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_115_trail_of_the_hunted">Pathfinder #115: Trail of the Hunted pg. 74</Link></p>
<p>Your bombs explode with such force that they throw targets off their guard and provides an opening for your allies.<br/><strong>Prerequisites:</strong> Bomb class feature, <Link to="/race/hobgoblin">hobgoblin</Link>.<br/><strong>Benefit:</strong> You can reduce your bomb damage by one die to give it the ability to distract the creature it strikes. If a creature takes a direct hit from your bomb, it must succeed at a Reflex saving throw against the bomb's DC or be unable to make attacks of opportunity for 1 round. This is in addition to any other effects the bomb would normally have.<br/><strong>Normal:</strong> The target of a bomb does not get a saving throw to avoid the bomb's effects.</p>
</>};
const _diva_advance = {title: "Diva Advance", jsx: <><h2 id="feat-diva_advance-diva-advance-combat">Diva Advance (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 176</Link></p>
<p>You stride forward with confidence, trusting your performance to protect you as much as your arms and armor.<br/><strong>Prerequisites:</strong> Cha 17, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/diva_strike">Diva Strike</Link>, <Link to="/feat/diva_style">Diva Style</Link>, <Link to="/feat/improved_feint">Improved Feint</Link>, base attack bonus +11 or bard level 11th.<br/><strong>Benefit:</strong> While using Diva Style, you do not provoke attacks of opportunity from creatures you have successfully feinted against. Additionally, you can <Link to="/rule/feint">feint</Link> against a creature using Diva Style from up to 30 feet away.</p>
</>};
const _diva_strike = {title: "Diva Strike", jsx: <><h2 id="feat-diva_strike-diva-strike-combat">Diva Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 176</Link></p>
<p>Those distracted by your performance leave themselves open to vicious attacks.<br/><strong>Prerequisites:</strong> Cha 15; <Link to="/feat/combat_expertise">Combat Expertise</Link>; <Link to="/feat/diva_style">Diva Style</Link>; <Link to="/feat/improved_feint">Improved Feint</Link>; base attack bonus +7 or bard level 7th.<br/><strong>Benefit:</strong> While using Diva Style, the first time you hit with a melee weapon in a round, you deal an additional amount of damage equal to your Charisma modifier to a target that is denied its Dexterity bonus to AC. This damage is precision-based, and is not multiplied on a critical hit.</p>
</>};
const _diva_style = {title: "Diva Style", jsx: <><h2 id="feat-diva_style-diva-style-combat-style">Diva Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 176</Link></p>
<p>You employ song, dance, or some other method of performance to distract your enemies from the battle at hand.<br/><strong>Prerequisites:</strong> Cha 13; base attack bonus +1 or bard level 1st.<br/><strong>Benefit:</strong> While using this style, you can use any Perform skill in place of <Link to="/skill/bluff">Bluff</Link> to feint in combat. You can attempt a Perform check to feint as a move action when you begin a <Link to="/ability/bardic_performance">bardic performance</Link>.</p>
</>};
const _diverse_obedience = {title: "Diverse Obedience", jsx: <><h2 id="feat-diverse_obedience-diverse-obedience">Diverse Obedience</h2>
<p><strong>Sources</strong> <Link to="/source/divine_anthology">Divine Anthology pg. 11</Link></p>
<p>Your intense faith in your deity allows you to gain boons not granted to most followers.<br/><strong>Prerequisites:</strong> <Link to="/feat/deific_obedience">Deific Obedience</Link>, Knowledge (religion) 5 ranks, alignment must match that of your worshiped deity.<br/><strong>Benefit:</strong> You are treated as though you had 2 more Hit Dice than you actually do for the purposes of determining what divine boons you gain as a result of performing your deity's obedience. Diverse Obedience doesn't allow access to divine boons granted through prestige classes early, as those boons are tied to prestige class levels gained, not overall Hit Dice. If you take levels in a prestige class or archetype that offers accelerated access to a boon, this benefit may be superfluous.</p>
<p>Additionally, whenever you would gain a boon as a result of your Deific Obedience feat (and not through a prestige class), you can choose among the options available for evangelist, exalted, or sentinel boons. Once you make the selection, it is permanent, but you can choose from a different category each time you gain a new boon as you increase your Hit Dice.</p>
</>};
const _diverse_palate = {title: "Diverse Palate", jsx: <><h2 id="feat-diverse_palate-diverse-palate">Diverse Palate</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 100</Link></p>
<p>Your taste for blood is broader than that of other dhampirs.<br/><strong>Prerequisites:</strong> <Link to="/feat/blood_drinker">Blood Drinker</Link>, <Link to="/race/dhampir">dhampir</Link>.<br/><strong>Benefit:</strong> Choose a humanoid subtype or the monstrous humanoid type. You may use your Blood Drinker feat on creatures of this subtype or type.<br/><strong>Special:</strong> You can take this feat multiple times. Each time you select it, choose a new humanoid subtype or the monstrous humanoid.</p>
</>};
const _diversion_shot = {title: "Diversion Shot", jsx: <><h2 id="feat-diversion_shot-diversion-shot-combat-teamwork">Diversion Shot (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 19</Link></p>
<p>You can use your shots to distract opponents.<br/><strong>Prerequisites:</strong> <Link to="/feat/stealthy">Stealthy</Link>, <Link to="/feat/target_of_opportunity">Target of Opportunity</Link>.<br/><strong>Benefit:</strong> When you hit a target using Target of Opportunity, the ally who triggered your ranged attack can attempt a Stealth check to hide from your target as an immediate action, even if your target is aware of your ally's presence. Your ally must also have this feat to benefit from this effect. This Stealth check applies only to the target you hit, and the stealth ends if the ally takes any action other than to move into <Link to="/rule/cover">cover</Link> or <Link to="/rule/concealment">concealment</Link>.</p>
</>};
const _divert_harm = {title: "Divert Harm", jsx: <><h2 id="feat-divert_harm-divert-harm-combat">Divert Harm (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion pg. 25</Link></p>
<p>You know how to throw your enemies into harm's way at the last second.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, base attack bonus +6, <Link to="/ability/evasion">evasion</Link> class feature.<br/><strong>Benefit:</strong> Whenever you are the target of an area-of-effect attack that normally deals half damage on a successful Reflex save (such as a <Link to="/spell/fireball">fireball</Link> spell or dragon's breath weapon), you may, as an immediate action, wrestle an adjacent foe into harm's way. This does not alter the position of you or your opponent, but your opponent must attempt a Reflex save against the attack in your place. If your opponent fails, it takes half damage from the attack and you take none; if it succeeds, it takes no damage and you take damage as normal as though you'd failed your saving throw (though this damage is still reduced by abilities such as <Link to="/ability/improved_evasion">improved evasion</Link>). This feat works even if the opponent was already in the affected area of the attack (so it is possible that an unlucky opponent could take as much as 1-1/2 times the damage normally possible from the attack). You can use this ability only on a foe within one size category of yourself.</p>
</>};
const _divination_guide = {title: "Divination Guide", jsx: <><h2 id="feat-divination_guide-divination-guide">Divination Guide</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 210</Link>, <Link to="/source/faiths_of_purity">Faiths of Purity pg. 24</Link></p>
<p>You deity grants you greater guidance and divine insight.<br/><strong>Prerequisites:</strong> Caster level 3rd, ability to cast <Link to="/spell/augury">augury</Link> or <Link to="/spell/divination">divination</Link>, must worship a deity.<br/><strong>Benefit:</strong> Whenever you cast <em>augury</em> or <em>divination,</em> you receive further guidance from your deity's agents. You gain a +1 sacred bonus if your worship a good deity or a +1 profane bonus if you worship an evil deity (if you worship a neutral deity the type of bonus is either determined by the type of energy you channel with the channel energy class feature or, if you don't have that class ability, your choice upon taking this feat) on all saving throws for 1 minute per caster level of the augury or divination spell you cast.</p>
</>};
const _divine_barrier = {title: "Divine Barrier", jsx: <><h2 id="feat-divine_barrier-divine-barrier">Divine Barrier</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 210</Link></p>
<p>You have trained in the art of blocking breath weapons.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_energy">Channel energy</Link> class feature, worshiper of <Link to="/faith/apsu">Apsu</Link>.<br/><strong>Benefit:</strong> When you are within an area effect that deals acid, cold, electricity, or fire damage, you can expend one use of your channel energy ability as an immediate action to shield yourself and all allies within 30 feet. You and allies within your shield only take half damage if they fail their save against the effect, and those who make a successful save take no damage from the effect.</p>
</>};
const _divine_communion = {title: "Divine Communion", jsx: <><h2 id="feat-divine_communion-divine-communion">Divine Communion</h2>
<p><strong>Sources</strong> <Link to="/source/divine_anthology">Divine Anthology pg. 11</Link></p>
<p>Your close, personal connection with your deity grants you insight into his or her wishes.<br/><strong>Prerequisites:</strong> Wisdom 13, alignment must match that of your worshiped deity.<br/><strong>Benefit:</strong> Once per day as a swift action, you can ponder whether or not your deity would approve or disapprove of a particular course of action, and whether that action would impact your alignment. The GM decides if the action is one your deity would approve of, and if it is, you gain an insight bonus equal to your Wisdom modifier (minimum of +1) on any d20 roll made in association with that action during this round. For every 3 ranks you have in Knowledge (religion), you can use this ability an additional time per day, to a maximum of 6 times a day.</p>
</>};
